code_examples.insecureCode:
// ❌ Insecure: Route exists but has no auth check
// The dev thinks nobody will guess this long URL
app.get('/admin-panel-secret-9912', (req, res) => {
  res.render('admin_dashboard');
});

code_examples.secureCode:
// ✓ Secure: Every route, no matter how 'hidden', requires auth
app.get('/dashboard', isAdmin, (req, res) => {
  res.render('admin_dashboard');
});

// And a global 404 for anything not explicitly allowed
app.use((req, res) => res.status(404).send('Not Found'));
